solvers
{
    cellDisplacement
    {
        solver          GAMG;
        smoother        GaussSeidel;
        tolerance       1e-7;
        relTol          0.001;
    }

    /*
    p_rgh
    {
        solver PCG;
        preconditioner DIC;
        tolerance 1e-7;
        relTol 0.01;
        minIter 3;
        maxIter 1000;
    }
    */

    p_rgh
    {
        solver           GAMG;
        tolerance        1e-7;
        relTol           0.01;
        minIter          1;
        maxIter          200;
        smoother         DIC; // DIC; //DICGaussSeidel; //FDIC;
        agglomerator     algebraicPair;
    }

    "(e|U|k|epsilon)"
    {
        solver          PBiCGStab;
        preconditioner  DILU;
        tolerance       1e-08;
        relTol          0.001;
    }
}

SIMPLE
{
    nNonOrthogonalCorrectors 2;
    pRefCell        0;
    pRefValue       0;

    residualControl
    {
        p_rgh           1e-5;
        U               1e-4;
        e               1e-4;

        "(k|epsilon)" 1e-4;
    }
}

relaxationFactors
{
    fields
    {
        p_rgh           0.7;
    }

    equations
    {
        U               0.5;
        e               0.5;
        k               0.5;
        epsilon         0.5;
    }
}


